      children: `
        .dashboard-page {
          --accent: #6366f1;
        }

        .loading-container {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          padding: 100px 20px;
        }

        .loading-container p {
          margin-top: 16px;
          color: var(--text-muted);
        }

        /* Header */
        .page-header-modern {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          margin-bottom: 24px;
          flex-wrap: wrap;
          gap: 16px;
        }

        .header-title h2 {
          font-size: 24px;
          font-weight: 700;
          color: var(--text);
          margin-bottom: 4px;
        }

        .header-title p {
          font-size: 14px;
          color: var(--text-muted);
        }

        .header-actions {
          display: flex;
          gap: 10px;
          align-items: center;
        }

        .btn-icon {
          width: 40px;
          height: 40px;
          padding: 0;
          display: flex;
          align-items: center;
          justify-content: center;
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 8px;
          color: var(--text-muted);
          cursor: pointer;
          transition: all 0.15s;
        }

        .btn-icon:hover {
          border-color: var(--accent);
          color: var(--accent);
        }

        /* Stats */
        .stats-row {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 16px;
          margin-bottom: 24px;
        }

        .stat-card-modern {
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 12px;
          padding: 20px;
          display: flex;
          align-items: center;
          gap: 16px;
          transition: all 0.2s;
        }

        .stat-card-modern:hover {
          border-color: var(--accent);
          transform: translateY(-2px);
        }

        .stat-icon {
          width: 48px;
          height: 48px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .stat-content {
          display: flex;
          flex-direction: column;
        }

        .stat-value {
          font-size: 28px;
          font-weight: 700;
          color: var(--text);
          line-height: 1;
        }

        .stat-label {
          font-size: 13px;
          color: var(--text-muted);
          margin-top: 4px;
        }

        /* Filters */
        .filters-section {
          display: flex;
          justify-content: space-between;
          align-items: center;
          gap: 16px;
          margin-bottom: 24px;
          flex-wrap: wrap;
        }

        .search-filter {
          position: relative;
          flex: 1;
          min-width: 250px;
          max-width: 400px;
        }

        .search-filter .search-icon {
          position: absolute;
          left: 14px;
          top: 50%;
          transform: translateY(-50%);
          color: var(--text-muted);
        }

        .search-filter input {
          width: 100%;
          padding: 10px 14px 10px 40px;
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 8px;
          font-size: 14px;
          color: var(--text);
          outline: none;
        }

        .search-filter input:focus {
          border-color: var(--accent);
        }

        .period-tabs {
          display: flex;
          background: var(--bg-2);
          border: 1px solid var(--border);
          border-radius: 8px;
          overflow: hidden;
        }

        .period-tab {
          padding: 10px 16px;
          border: none;
          background: none;
          color: var(--text-muted);
          font-size: 13px;
          cursor: pointer;
          transition: all 0.15s;
        }

        .period-tab:hover {
          color: var(--text);
        }

        .period-tab.active {
          background: var(--accent);
          color: white;
        }

        /* Charts */
        .charts-grid {
          display: grid;
          grid-template-columns: 2fr 1fr;
          gap: 16px;
          margin-bottom: 24px;
        }

        .chart-card {
          min-height: 280px;
        }

        .card-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 16px;
        }

        .card-header h3 {
          font-size: 16px;
          font-weight: 600;
          color: var(--text);
        }

        .card-subtitle {
          font-size: 12px;
          color: var(--text-muted);
        }

        .chart-container {
          height: 200px;
        }

        .line-chart-svg {
          width: 100%;
          height: 160px;
        }

        .chart-labels {
          display: flex;
          justify-content: space-between;
          padding: 8px 0 0;
          font-size: 11px;
          color: var(--text-muted);
        }

        .bar-chart-container {
          display: flex;
          flex-direction: column;
          gap: 12px;
        }

        .bar-item {
          display: flex;
          align-items: center;
          gap: 12px;
        }

        .bar-label {
          width: 80px;
          font-size: 12px;
          color: var(--text-muted);
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }

        .bar-track {
          flex: 1;
          height: 8px;
          background: var(--bg-3);
          border-radius: 4px;
          overflow: hidden;
        }

        .bar-fill {
          height: 100%;
          background: var(--accent);
          border-radius: 4px;
          transition: width 0.3s ease;
        }

        .bar-value {
          width: 40px;
          text-align: right;
          font-size: 12px;
          font-weight: 500;
          color: var(--text);
        }

        .pie-chart-container {
          padding: 16px 0;
        }

        .pie-legend {
          display: flex;
          flex-direction: column;
          gap: 10px;
        }

        .legend-item {
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .legend-dot {
          width: 10px;
          height: 10px;
          border-radius: 2px;
        }

        .legend-label {
          flex: 1;
          font-size: 13px;
          color: var(--text);
        }

        .legend-value {
          font-size: 13px;
          font-weight: 600;
          color: var(--text-muted);
        }

        /* Tables */
        .tables-grid {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 16px;
          margin-bottom: 24px;
        }

        .table-container {
          overflow: hidden;
        }

        .modern-table {
          width: 100%;
          border-collapse: collapse;
        }

        .modern-table thead {
          background: var(--bg-3);
        }

        .modern-table th {
          padding: 12px 16px;
          font-size: 11px;
          font-weight: 600;
          text-transform: uppercase;
          letter-spacing: 0.5px;
          color: var(--text-muted);
          text-align: left;
        }

        .modern-table td {
          padding: 12px 16px;
          font-size: 13px;
          border-top: 1px solid var(--border);
        }

        .modern-table tbody tr {
          transition: background 0.15s;
        }

        .modern-table tbody tr:hover {
          background: rgba(99, 102, 241, 0.04);
        }

        .product-cell {
          font-weight: 500;
        }

        .qty-cell {
